const email = _Constants.default.resetPasswordEmail;
const validPassword = "ValidPass123!"; // meets all rules
// Step 1 – Trigger forgot password request manually via API
cy.request({
  method: "POST",
  url: `${Cypress.config("baseUrl")}/api/forgotPassword/${email}`,
  failOnStatusCode: false
}).then(response => {
  expect(response.status).to.eq(200);
  expect(response.body.msg).to.eq("Email sent successfully");
  expect(response.body.resetToken).to.exist;
  const token = response.body.resetToken;
  // Step 2 – Open reset page
  cy.visit(`${Cypress.config("baseUrl")}/resetpassword/${token}`);
  // Step 3 – Enter valid password
  _LidarViewer.default.NewPasswordField.type(validPassword);
  // Step 4 – Validation rules
  const rules = ["Should be at least 8 characters long.", "Should contain at least one number.", "Should contain at least one lowercase letter.", "Should contain at least one uppercase letter.", "Should contain at least one special character."];
  rules.forEach(rule => {
    cy.contains("span", rule).parent() // the <div style="color: ...">
    .should("have.attr", "style").and("include", "color: green"); // final expected state
  });
});

